oke-width=\"3\"></line>\n        <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n        <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n        <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n        <line x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"></line>\n        <line x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"></line>\n        <line x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"></line>\n        <line x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"></line>\n        <line x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"></line>\n        <line x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"></line>\n      </svg>\n    </div>\n  </div>\n  <div data-rise=\"\" data-d=\"6\" style=\"font-size:74px;font-weight:900;letter-spacing:-.01em;margin-top:90px;\">SƠ ĐỒ <span style=\"color:#E2673B;\">=</span><br>MẶT CẦN ĐÀN</div>\n</section>", "<section data-label=\"6 dây đàn\" data-speaker-notes=\"Sáu đường dọc chính là sáu dây đàn. Bên trái là dây to nhất, bên phải là dây nhỏ nhất.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:120px 90px;\">\n  <div data-rise=\"\" data-d=\"6\" style=\"font-size:150px;font-weight:900;line-height:.9;letter-spacing:-.02em;margin-bottom:70px;\">6 DÂY ĐÀN</div>\n  <div data-rise=\"\" data-d=\"1\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:470px;height:auto;overflow:visible;\">\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"></rect>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line data-str=\"0\" data-pop=\"\" data-d=\"1\" x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"5\"></line>\n      <line data-str=\"1\" data-pop=\"\" data-d=\"2\" x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"4\"></line>\n      <line data-str=\"2\" data-pop=\"\" data-d=\"3\" x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"3.2\"></line>\n      <line data-str=\"3\" data-pop=\"\" data-d=\"4\" x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"2.6\"></line>\n      <line data-str=\"4\" data-pop=\"\" data-d=\"5\" x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"2\"></line>\n      <line data-str=\"5\" data-pop=\"\" data-d=\"6\" x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#E2673B\" stroke-width=\"1.5\"></line>\n    </svg>\n  </div>\n  <div data-rise=\"\" data-d=\"7\" style=\"display:flex;align-items:center;gap:22px;margin-top:80px;font-size:46px;font-weight:600;color:#5C564B;\">\n    <span style=\"font-size:60px;font-weight:800;color:#1C1B19;\">DÂY TO</span>\n    <span style=\"color:#E2673B;\">→</span>\n    <span style=\"font-size:38px;\">dây nhỏ</span>\n  </div>\n</section>", "<section data-label=\"Ngăn đàn\" data-speaker-notes=\"Các đường ngang chia cần đàn thành từng ngăn. Đếm từ trên xuống: ngăn 1, ngăn 2, ngăn 3.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:120px 90px;\">\n  <div data-rise=\"\" data-d=\"5\" style=\"font-size:96px;font-weight:900;line-height:.92;letter-spacing:-.02em;\">ĐƯỜNG NGANG</div>\n  <div data-rise=\"\" data-d=\"6\" style=\"font-size:56px;font-weight:600;color:#E2673B;margin-top:20px;margin-bottom:64px;\">= NGĂN ĐÀN</div>\n  <div data-rise=\"\" data-d=\"1\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:440px;height:auto;overflow:visible;\">\n      <rect data-pop=\"\" data-d=\"2\" x=\"40\" y=\"73\" width=\"220\" height=\"77\" fill=\"#E2673B\" opacity=\".16\"></rect>\n      <rect data-pop=\"\" data-d=\"3\" x=\"40\" y=\"150\" width=\"220\" height=\"80\" fill=\"#E2673B\" opacity=\".28\"></rect>\n      <rect data-pop=\"\" data-d=\"4\" x=\"40\" y=\"230\" width=\"220\" height=\"80\" fill=\"#E2673B\" opacity=\".16\"></rect>\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"></rect>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#1C1B19\" stroke-width=\"3.4\"></line>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#1C1B19\" stroke-width=\"3.4\"></line>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#1C1B19\" stroke-width=\"3.4\"></line>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"></line>\n      <line x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"></line>\n      <line x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"></line>\n      <line x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"></line>\n      <line x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"></line>\n      <line x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"></line>\n      <text data-pop=\"\" data-d=\"2\" x=\"22\" y=\"120\" text-anchor=\"middle\" font-size=\"26\" font-weight=\"800\" fill=\"#E2673B\" font-family=\"'Be Vietnam Pro'\">1</text>\n      <text data-pop=\"\" data-d=\"3\" x=\"22\" y=\"200\" text-anchor=\"middle\" font-size=\"26\" font-weight=\"800\" fill=\"#E2673B\" font-family=\"'Be Vietnam Pro'\">2</text>\n      <text data-pop=\"\" data-d=\"4\" x=\"22\" y=\"280\" text-anchor=\"middle\" font-size=\"26\" font-weight=\"800\" fill=\"#E2673B\" font-family=\"'Be Vietnam Pro'\">3</text>\n    </svg>\n  </div>\n  <div style=\"display:flex;gap:20px;margin-top:70px;\">\n    <div data-pop=\"\" data-d=\"5\" style=\"width:110px;height:110px;border-radius:22px;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:54px;font-weight:800;\">1</div>\n    <div data-pop=\"\" data-d=\"6\" style=\"width:110px;height:110px;border-radius:22px;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:54px;font-weight:800;\">2</div>\n    <div data-pop=\"\" data-d=\"7\" style=\"width:110px;height:110px;border-radius:22px;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:54px;font-weight:800;\">3</div>\n  </div>\n</section>", "<section data-label=\"Chấm đen\" data-speaker-notes=\"Chấm đen cho biết chỗ đặt ngón tay. Ở đây có hai chấm: dây 5 và dây 4, đều ở ngăn 2.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:120px 90px;\">\n  <div data-rise=\"\" data-d=\"4\" style=\"font-size:150px;font-weight:900;line-height:.9;letter-spacing:-.02em;\">CHẤM ĐEN</div>\n  <div data-rise=\"\" data-d=\"5\" style=\"font-size:50px;font-weight:600;color:#5C564B;margin-top:24px;margin-bottom:70px;\">Đặt ngón tay ở đây</div>\n  <div data-rise=\"\" data-d=\"1\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:480px;height:auto;overflow:visible;\">\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"></rect>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"></line>\n      <line x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"></line>\n      <line x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"></line>\n      <line x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"></line>\n      <line x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"></line>\n      <line x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"></line>\n      <circle data-glow=\"\" cx=\"84\" cy=\"190\" r=\"28\" fill=\"#E2673B\" opacity=\".22\"></circle>\n      <circle data-glow=\"\" cx=\"128\" cy=\"190\" r=\"28\" fill=\"#E2673B\" opacity=\".22\"></circle>\n      <circle data-pop=\"\" data-d=\"2\" cx=\"84\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n      <circle data-pop=\"\" data-d=\"3\" cx=\"128\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n    </svg>\n  </div>\n</section>", "<section data-label=\"Số = ngón tay\" data-speaker-notes=\"Số trong chấm là số ngón tay trái. 1 trỏ, 2 giữa, 3 áp út, 4 út. Hợp âm Em dùng ngón 2 và ngón 3.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:120px 90px;\">\n  <div data-rise=\"\" data-d=\"3\" style=\"font-size:104px;font-weight:900;line-height:.92;letter-spacing:-.02em;\">SỐ <span style=\"color:#E2673B;\">=</span> NGÓN TAY</div>\n  <div data-rise=\"\" data-d=\"1\" style=\"flex:none;display:flex;flex-direction:column;align-items:center;margin-top:70px;\">\n    <div style=\"display:flex;align-items:flex-end;gap:22px;\">\n      <div style=\"display:flex;flex-direction:column;align-items:center;gap:20px;\">\n        <div style=\"width:64px;height:64px;border-radius:50%;background:#fff;border:3px solid #1C1B19;display:flex;align-items:center;justify-content:center;font-size:34px;font-weight:800;\">1</div>\n        <div style=\"width:74px;height:200px;background:#E7DFCB;border-radius:38px 38px 10px 10px;\"></div>\n        <div style=\"font-size:32px;font-weight:600;color:#5C564B;\">Trỏ</div>\n      </div>\n      <div style=\"display:flex;flex-direction:column;align-items:center;gap:20px;\">\n        <div style=\"width:64px;height:64px;border-radius:50%;background:#E2673B;color:#fff;display:flex;align-items:center;justify-content:center;font-size:34px;font-weight:800;\">2</div>\n        <div style=\"width:74px;height:248px;background:#E2673B;border-radius:38px 38px 10px 10px;\"></div>\n        <div style=\"font-size:32px;font-weight:800;color:#E2673B;\">Giữa</div>\n      </div>\n      <div style=\"display:flex;flex-direction:column;align-items:center;gap:20px;\">\n        <div style=\"width:64px;height:64px;border-radius:50%;background:#E2673B;color:#fff;display:flex;align-items:center;justify-content:center;font-size:34px;font-weight:800;\">3</div>\n        <div style=\"width:74px;height:220px;background:#E2673B;border-radius:38px 38px 10px 10px;\"></div>\n        <div style=\"font-size:32px;font-weight:800;color:#E2673B;\">Áp út</div>\n      </div>\n      <div style=\"display:flex;flex-direction:column;align-items:center;gap:20px;\">\n        <div style=\"width:64px;height:64px;border-radius:50%;background:#fff;border:3px solid #1C1B19;display:flex;align-items:center;justify-content:center;font-size:34px;font-weight:800;\">4</div>\n        <div style=\"width:74px;height:160px;background:#E7DFCB;border-radius:38px 38px 10px 10px;\"></div>\n        <div style=\"font-size:32px;font-weight:600;color:#5C564B;\">Út</div>\n      </div>\n    </div>\n    <div style=\"width:400px;height:84px;background:#E7DFCB;border-radius:0 0 60px 60px;margin-top:46px;\"></div>\n  </div>\n  <div data-rise=\"\" data-d=\"5\" style=\"font-size:48px;font-weight:600;color:#5C564B;margin-top:74px;\">Em: ngón <b style=\"color:#1C1B19;\">2</b> &amp; ngón <b style=\"color:#1C1B19;\">3</b> ở ngăn 2</div>\n</section>", "<section data-label=\"O = dây buông\" data-speaker-notes=\"Ký hiệu O ở phía trên là dây buông: không bấm nhưng vẫn gảy cho rung lên. Bấm nút để nghe.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:120px 90px;\">\n  <div data-pop=\"\" data-d=\"1\" style=\"font-size:280px;line-height:.78;font-weight:800;color:#2F9E6E;\">O</div>\n  <div data-rise=\"\" data-d=\"3\" style=\"font-size:84px;font-weight:900;margin-top:10px;\">DÂY BUÔNG</div>\n  <div data-rise=\"\" data-d=\"4\" style=\"font-size:46px;font-weight:600;color:#5C564B;margin-top:12px;margin-bottom:64px;\">Không bấm — vẫn gảy</div>\n  <div data-rise=\"\" data-d=\"2\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:420px;height:auto;overflow:visible;\">\n      <circle data-glow=\"\" cx=\"40\" cy=\"42\" r=\"13\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"4\"></circle>\n      <circle data-glow=\"\" cx=\"172\" cy=\"42\" r=\"13\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"4\"></circle>\n      <circle data-glow=\"\" cx=\"216\" cy=\"42\" r=\"13\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"4\"></circle>\n      <circle data-glow=\"\" cx=\"260\" cy=\"42\" r=\"13\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"4\"></circle>\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"></rect>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"></line>\n      <line x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"></line>\n      <line x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"></line>\n      <line x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"></line>\n      <line x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"></line>\n      <line x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"></line>\n      <circle cx=\"84\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n      <circle cx=\"128\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n    </svg>\n  </div>\n  <button data-rise=\"\" data-d=\"5\" style=\"margin-top:64px;display:inline-flex;align-items:center;gap:18px;padding:28px 56px;border:none;border-radius:100px;background:#2F9E6E;color:#fff;font-family:'Be Vietnam Pro',sans-serif;font-size:42px;font-weight:700;cursor:pointer;\">▶ Nghe dây buông</button>\n</section>", "<section data-label=\"X = không gảy\" data-speaker-notes=\"Ký hiệu X là dây không gảy. Tay phải bỏ qua dây có dấu X, không cho nó kêu.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:120px 90px;\">\n  <div data-pop=\"\" data-d=\"1\" style=\"font-size:280px;line-height:.78;font-weight:900;color:#B23B2E;\">✕</div>\n  <div data-rise=\"\" data-d=\"3\" style=\"font-size:84px;font-weight:900;margin-top:10px;\">KHÔNG GẢY</div>\n  <div data-rise=\"\" data-d=\"4\" style=\"font-size:46px;font-weight:600;color:#5C564B;margin-top:12px;margin-bottom:64px;\">Tay phải bỏ qua dây này</div>\n  <div data-rise=\"\" data-d=\"2\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:420px;height:auto;overflow:visible;\">\n      <g data-pop=\"\" data-d=\"2\">\n        <line x1=\"31\" y1=\"33\" x2=\"49\" y2=\"51\" stroke=\"#B23B2E\" stroke-width=\"5\" stroke-linecap=\"round\"></line>\n        <line x1=\"49\" y1=\"33\" x2=\"31\" y2=\"51\" stroke=\"#B23B2E\" stroke-width=\"5\" stroke-linecap=\"round\"></line>\n      </g>\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"></rect>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#C9C2B2\" stroke-width=\"5\" stroke-dasharray=\"6 7\"></line>\n      <line x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"></line>\n      <line x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"></line>\n      <line x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"></line>\n      <line x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"></line>\n      <line x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"></line>\n    </svg>\n  </div>\n</section>", "<section id=\"s9\" data-label=\"Thực hành Em\" data-speaker-notes=\"Giờ ráp lại với hợp âm Em. Nhìn sơ đồ, đặt ngón 2 và 3, rồi gảy từng dây từ trên xuống. Bấm nút để nghe.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:100px 90px;\">\n  <div data-rise=\"\" data-d=\"1\" style=\"font-size:40px;font-weight:700;letter-spacing:.2em;color:#E2673B;text-transform:uppercase;\">Hợp âm</div>\n  <div data-rise=\"\" data-d=\"2\" style=\"font-size:170px;line-height:.86;font-weight:900;letter-spacing:-.02em;margin-bottom:30px;\">Em</div>\n  <div data-rise=\"\" data-d=\"2\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:420px;height:auto;overflow:visible;\">\n      <circle cx=\"40\" cy=\"42\" r=\"12\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"3.4\"></circle>\n      <circle cx=\"172\" cy=\"42\" r=\"12\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"3.4\"></circle>\n      <circle cx=\"216\" cy=\"42\" r=\"12\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"3.4\"></circle>\n      <circle cx=\"260\" cy=\"42\" r=\"12\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"3.4\"></circle>\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"></rect>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line data-str=\"0\" x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"></line>\n      <line data-str=\"1\" x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"></line>\n      <line data-str=\"2\" x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"></line>\n      <line data-str=\"3\" x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"></line>\n      <line data-str=\"4\" x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"></line>\n      <line data-str=\"5\" x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"></line>\n      <circle cx=\"84\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n      <text x=\"84\" y=\"199\" text-anchor=\"middle\" font-size=\"25\" font-weight=\"800\" fill=\"#fff\" font-family=\"'Be Vietnam Pro'\">2</text>\n      <circle cx=\"128\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n      <text x=\"128\" y=\"199\" text-anchor=\"middle\" font-size=\"25\" font-weight=\"800\" fill=\"#fff\">3</text>\n    </svg>\n  </div>\n  <div style=\"display:flex;justify-content:center;flex-wrap:wrap;gap:18px 40px;font-size:38px;font-weight:600;margin-top:60px;max-width:840px;\">\n    <div data-slide=\"\" data-d=\"3\" style=\"display:flex;align-items:center;gap:16px;\"><span style=\"width:50px;height:50px;border-radius:50%;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:26px;font-weight:800;flex:none;\">1</span>Nhìn sơ đồ</div>\n    <div data-slide=\"\" data-d=\"4\" style=\"display:flex;align-items:center;gap:16px;\"><span style=\"width:50px;height:50px;border-radius:50%;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:26px;font-weight:800;flex:none;\">2</span>Đặt ngón 2 &amp; 3</div>\n    <div data-slide=\"\" data-d=\"5\" style=\"display:flex;align-items:center;gap:16px;\"><span style=\"width:50px;height:50px;border-radius:50%;background:#1C1B19;color:#fff;display:flex;align-items:center;justify-content:center;font-size:26px;font-weight:800;flex:none;\">3</span>Gảy từng dây</div>\n    <div data-slide=\"\" data-d=\"6\" style=\"display:flex;align-items:center;gap:16px;\"><span style=\"width:50px;height:50px;border-radius:50%;background:#2F9E6E;color:#fff;display:flex;align-items:center;justify-content:center;font-size:26px;font-weight:800;flex:none;\">4</span>Nghe vang rõ</div>\n  </div>\n  <button data-rise=\"\" data-d=\"7\" style=\"margin-top:64px;display:inline-flex;align-items:center;gap:18px;padding:30px 64px;border:none;border-radius:100px;background:#E2673B;color:#fff;font-family:'Be Vietnam Pro',sans-serif;font-size:46px;font-weight:800;cursor:pointer;\">▶ Gảy hợp âm Em</button>\n</section>", "<section id=\"s10\" data-label=\"Kiểm tra âm\" data-speaker-notes=\"Gảy từng dây để kiểm tra. Dây vang rõ là đạt. Nếu dây bị tịt hoặc rè thì chỉnh lại ngón tay rồi gảy lại.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:100px 90px;\">\n  <div data-rise=\"\" data-d=\"1\" style=\"font-size:118px;font-weight:900;letter-spacing:-.02em;margin-bottom:50px;\">KIỂM TRA</div>\n  <div data-rise=\"\" data-d=\"2\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:360px;height:auto;overflow:visible;\">\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"></rect>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line data-str=\"0\" x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"></line>\n      <line data-str=\"1\" x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"></line>\n      <line data-str=\"2\" x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"></line>\n      <line data-str=\"3\" x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"></line>\n      <line data-str=\"4\" x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"></line>\n      <line data-str=\"5\" x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"></line>\n      <circle cx=\"84\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n      <circle cx=\"128\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n    </svg>\n  </div>\n  <div style=\"width:100%;max-width:760px;margin-top:60px;\">\n    <div data-rise=\"\" data-d=\"3\" style=\"display:flex;align-items:center;gap:20px;padding:28px 38px;border-radius:22px;background:#E6F2EB;margin-bottom:20px;\">\n      <span style=\"font-size:52px;color:#2F9E6E;\">✓</span>\n      <span style=\"font-size:52px;font-weight:800;color:#2F9E6E;\">VANG RÕ</span>\n      <span style=\"font-size:34px;font-weight:500;color:#5C564B;margin-left:auto;\">kêu trong, ngân</span>\n    </div>\n    <div data-rise=\"\" data-d=\"4\" style=\"display:flex;align-items:center;gap:20px;padding:28px 38px;border-radius:22px;background:#F7E6E3;\">\n      <span style=\"font-size:52px;color:#B23B2E;\">✕</span>\n      <span style=\"font-size:52px;font-weight:800;color:#B23B2E;\">TỊT / RÈ</span>\n      <button style=\"margin-left:auto;padding:16px 32px;border:2px solid #B23B2E;background:transparent;color:#B23B2E;border-radius:100px;font-family:'Be Vietnam Pro',sans-serif;font-size:30px;font-weight:700;cursor:pointer;\">▶ nghe</button>\n    </div>\n    <div data-slide=\"\" data-d=\"5\" style=\"display:flex;align-items:center;justify-content:center;gap:22px;font-size:42px;font-weight:700;margin-top:44px;\">\n      <span style=\"color:#5C564B;\">SỬA LẠI TAY</span>\n      <span style=\"color:#E2673B;\">→</span>\n      <span style=\"color:#2F9E6E;\">VANG RÕ ✓</span>\n    </div>\n  </div>\n</section>", "<section data-label=\"Câu chốt\" data-speaker-notes=\"Nhớ một câu duy nhất: sơ đồ hợp âm là bản đồ của tay trái. Năm ký hiệu bên dưới là tất cả những gì cần đọc.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#1C1B19;color:#F6F3EC;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:120px 90px;\">\n  \n  <div data-rise=\"\" data-d=\"1\" style=\"font-size:38px;font-weight:600;letter-spacing:.34em;color:#E2673B;text-transform:uppercase;margin-bottom:30px;\">Nhớ một câu</div><h2 data-rise=\"\" data-d=\"2\" style=\"font-size:128px;line-height:.92;font-weight:900;letter-spacing:-.02em;margin:0;text-wrap:balance;\">SƠ ĐỒ<br>HỢP ÂM</h2>\n  <div data-rise=\"\" data-d=\"3\" style=\"font-size:70px;font-weight:800;color:#E2673B;margin-top:24px;\">là bản đồ của tay trái</div>\n  <div style=\"display:flex;flex-direction:column;gap:18px;margin-top:80px;width:100%;max-width:740px;\">\n    <div data-slide=\"\" data-d=\"4\" style=\"display:flex;align-items:center;gap:30px;padding:24px 34px;border-radius:20px;background:rgba(255,255,255,.06);text-align:left;\">\n      <svg viewBox=\"0 0 48 48\" style=\"width:54px;height:54px;flex:none;\"><line x1=\"10\" y1=\"6\" x2=\"10\" y2=\"42\" stroke=\"#F6F3EC\" stroke-width=\"4\"></line><line x1=\"20\" y1=\"6\" x2=\"20\" y2=\"42\" stroke=\"#F6F3EC\" stroke-width=\"3\"></line><line x1=\"30\" y1=\"6\" x2=\"30\" y2=\"42\" stroke=\"#F6F3EC\" stroke-width=\"2.2\"></line><line x1=\"39\" y1=\"6\" x2=\"39\" y2=\"42\" stroke=\"#F6F3EC\" stroke-width=\"1.6\"></line></svg>\n      <div style=\"font-size:42px;font-weight:700;\">Đường dọc</div>\n      <div style=\"font-size:38px;font-weight:500;color:#B7AE9C;margin-left:auto;\">dây đàn</div>\n    </div>\n    <div data-slide=\"\" data-d=\"5\" style=\"display:flex;align-items:center;gap:30px;padding:24px 34px;border-radius:20px;background:rgba(255,255,255,.06);text-align:left;\">\n      <svg viewBox=\"0 0 48 48\" style=\"width:54px;height:54px;flex:none;\"><line x1=\"6\" y1=\"12\" x2=\"42\" y2=\"12\" stroke=\"#F6F3EC\" stroke-width=\"3.4\"></line><line x1=\"6\" y1=\"24\" x2=\"42\" y2=\"24\" stroke=\"#F6F3EC\" stroke-width=\"3.4\"></line><line x1=\"6\" y1=\"36\" x2=\"42\" y2=\"36\" stroke=\"#F6F3EC\" stroke-width=\"3.4\"></line></svg>\n      <div style=\"font-size:42px;font-weight:700;\">Đường ngang</div>\n      <div style=\"font-size:38px;font-weight:500;color:#B7AE9C;margin-left:auto;\">ngăn đàn</div>\n    </div>\n    <div data-slide=\"\" data-d=\"6\" style=\"display:flex;align-items:center;gap:30px;padding:24px 34px;border-radius:20px;background:rgba(255,255,255,.06);text-align:left;\">\n      <svg viewBox=\"0 0 48 48\" style=\"width:54px;height:54px;flex:none;\"><circle cx=\"24\" cy=\"24\" r=\"15\" fill=\"#F6F3EC\"></circle></svg>\n      <div style=\"font-size:42px;font-weight:700;\">Chấm đen</div>\n      <div style=\"font-size:38px;font-weight:500;color:#B7AE9C;margin-left:auto;\">vị trí bấm</div>\n    </div>\n    <div data-slide=\"\" data-d=\"7\" style=\"display:flex;align-items:center;gap:30px;padding:24px 34px;border-radius:20px;background:rgba(255,255,255,.06);text-align:left;\">\n      <svg viewBox=\"0 0 48 48\" style=\"width:54px;height:54px;flex:none;\"><circle cx=\"24\" cy=\"24\" r=\"14\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"4.5\"></circle></svg>\n      <div style=\"font-size:42px;font-weight:700;color:#2F9E6E;\">O — dây buông</div>\n      <div style=\"font-size:38px;font-weight:500;color:#B7AE9C;margin-left:auto;\">vẫn gảy</div>\n    </div>\n    <div data-slide=\"\" data-d=\"8\" style=\"display:flex;align-items:center;gap:30px;padding:24px 34px;border-radius:20px;background:rgba(255,255,255,.06);text-align:left;\">\n      <svg viewBox=\"0 0 48 48\" style=\"width:54px;height:54px;flex:none;\"><line x1=\"13\" y1=\"13\" x2=\"35\" y2=\"35\" stroke=\"#B23B2E\" stroke-width=\"5\" stroke-linecap=\"round\"></line><line x1=\"35\" y1=\"13\" x2=\"13\" y2=\"35\" stroke=\"#B23B2E\" stroke-width=\"5\" stroke-linecap=\"round\"></line></svg>\n      <div style=\"font-size:42px;font-weight:700;color:#E07a6a;\">X — không gảy</div>\n      <div style=\"font-size:38px;font-weight:500;color:#B7AE9C;margin-left:auto;\">bỏ qua</div>\n    </div>\n  </div>\n</section>", "<section id=\"s12\" data-label=\"Bài tập\" data-speaker-notes=\"Bài tập: đặt đúng 2 ngón cho Em, gảy từng dây, sửa dây bị tịt cho đến khi cả hợp âm vang rõ. Chưa cần nhanh, chỉ cần đúng và rõ.\" style=\"width:100%;height:100%;box-sizing:border-box;background:#F6F3EC;color:#1C1B19;font-family:'Be Vietnam Pro',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:100px 90px;\">\n  \n  <div data-rise=\"\" data-d=\"2\" style=\"font-size:140px;line-height:.9;font-weight:900;letter-spacing:-.02em;margin-bottom:40px;\">BÀI TẬP</div>\n  <div data-rise=\"\" data-d=\"2\" style=\"flex:none;\">\n    <svg viewBox=\"0 0 300 440\" style=\"width:360px;height:auto;overflow:visible;\">\n      <circle cx=\"40\" cy=\"42\" r=\"12\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"3.4\"></circle>\n      <circle cx=\"172\" cy=\"42\" r=\"12\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"3.4\"></circle>\n      <circle cx=\"216\" cy=\"42\" r=\"12\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"3.4\"></circle>\n      <circle cx=\"260\" cy=\"42\" r=\"12\" fill=\"none\" stroke=\"#2F9E6E\" stroke-width=\"3.4\"></circle>\n      <rect x=\"36\" y=\"64\" width=\"228\" height=\"9\" rx=\"2\" fill=\"#1C1B19\"></rect>\n      <line x1=\"40\" y1=\"150\" x2=\"260\" y2=\"150\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"230\" x2=\"260\" y2=\"230\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"310\" x2=\"260\" y2=\"310\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line x1=\"40\" y1=\"390\" x2=\"260\" y2=\"390\" stroke=\"#CFC8B7\" stroke-width=\"3\"></line>\n      <line data-str=\"0\" x1=\"40\" y1=\"70\" x2=\"40\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"5\"></line>\n      <line data-str=\"1\" x1=\"84\" y1=\"70\" x2=\"84\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"4\"></line>\n      <line data-str=\"2\" x1=\"128\" y1=\"70\" x2=\"128\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"3\"></line>\n      <line data-str=\"3\" x1=\"172\" y1=\"70\" x2=\"172\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"2.4\"></line>\n      <line data-str=\"4\" x1=\"216\" y1=\"70\" x2=\"216\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.8\"></line>\n      <line data-str=\"5\" x1=\"260\" y1=\"70\" x2=\"260\" y2=\"390\" stroke=\"#1C1B19\" stroke-width=\"1.4\"></line>\n      <circle cx=\"84\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n      <text x=\"84\" y=\"199\" text-anchor=\"middle\" font-size=\"25\" font-weight=\"800\" fill=\"#fff\" font-family=\"'Be Vietnam Pro'\">2</text>\n      <circle cx=\"128\" cy=\"190\" r=\"21\" fill=\"#1C1B19\"></circle>\n      <text x=\"128\" y=\"199\" text-anchor=\"middle\" font-size=\"25\" font-weight=\"800\" fill=\"#fff\">3</text>\n    </svg>\n  </div>\n  <div style=\"display:flex;flex-direction:column;align-items:flex-start;gap:16px;font-size:40px;font-weight:600;margin-top:54px;\">\n    <div data-slide=\"\" data-d=\"3\" style=\"display:flex;align-items:center;gap:18px;\"><span style=\"color:#E2673B;font-size:34px;\">●</span>Đặt đúng 2 ngón cho Em</div>\n    <div data-slide=\"\" data-d=\"4\" style=\"display:flex;align-items:center;gap:18px;\"><span style=\"color:#E2673B;font-size:34px;\">●</span>Gảy từng dây, lắng nghe</div>\n    <div data-slide=\"\" data-d=\"5\" style=\"display:flex;align-items:center;gap:18px;\"><span style=\"color:#E2673B;font-size:34px;\">●</span>Sửa dây bị tịt / rè</div>\n    <div data-slide=\"\" data-d=\"6\" style=\"display:flex;align-items:center;gap:18px;\"><span style=\"color:#2F9E6E;font-size:34px;\">✓</span>Cả hợp âm vang rõ</div>\n  </div>\n  <div data-rise=\"\" data-d=\"7\" style=\"margin-top:56px;font-size:50px;font-weight:800;line-height:1.18;\">Chưa cần nhanh.<br><span style=\"color:#E2673B;\">Chỉ cần đúng và rõ.</span></div>\n</section>"], "end_times": [11.5, 22.4, 34.8, 49.1, 61.2, 79.7, 97.2, 110.9, 126.6, 145.1, 164.2, 182.8]}},
      {"id":"sd2","order":3,"logic":"NGAM","type":"checklist","title":"Tự kiểm tra","interactive":{"items":["Mình biết đường dọc là dây đàn, đường ngang là ngăn đàn","Mình biết chấm đen = đặt ngón, O = dây buông, X = không gảy","Mình đã thử bấm Em theo sơ đồ và gảy từng dây"]}},
      {"id":"sd3","order":4,"logic":"DAN","type":"text","title":"Câu chốt","content":"<div style='background:#2A2622;border-radius:10px;padding:22px 20px;color:#F4ECDF;'><div style='font-size:11px;font-weight:700;letter-spacing:0.16em;text-transform:uppercase;color:#D89B72;margin-bottom:10px;'>Câu chốt</div><div style='font-size:17px;line-height:1.5;'>Sơ đồ hợp âm là <b>bản đồ của tay trái</b>. Một lần hiểu — dùng được mãi mãi.</div></div>"}
